class Solution:
    def countCells(self, grid, pattern):
        m = len(grid)
        n = len(grid[0])
        # row-major string and the cell each flat index maps to
        row_cells = []
        row_str = []
        for r in range(m):
            for c in range(n):
                row_str.append(grid[r][c])
                row_cells.append((r, c))
        row_str = ''.join(row_str)
        # column-major string
        col_cells = []
        col_str = []
        for c in range(n):
            for r in range(m):
                col_str.append(grid[r][c])
                col_cells.append((r, c))
        col_str = ''.join(col_str)
        L = len(pattern)
        h = set()
        v = set()
        for s in range(0, len(row_str) - L + 1):
            if row_str[s:s + L] == pattern:
                for t in range(s, s + L):
                    h.add(row_cells[t])
        for s in range(0, len(col_str) - L + 1):
            if col_str[s:s + L] == pattern:
                for t in range(s, s + L):
                    v.add(col_cells[t])
        return len(h & v)

