class Solution:
    def countCells(self, grid, pattern):
        m = len(grid)
        n = len(grid[0])
        L = len(pattern)
        # KMP prefix function
        pi = [0] * L
        k = 0
        for i in range(1, L):
            while k > 0 and pattern[i] != pattern[k]:
                k = pi[k - 1]
            if pattern[i] == pattern[k]:
                k += 1
            pi[i] = k

        def matches(getch, total):
            res = []
            k = 0
            for i in range(total):
                ch = getch(i)
                while k > 0 and ch != pattern[k]:
                    k = pi[k - 1]
                if ch == pattern[k]:
                    k += 1
                if k == L:
                    res.append(i - L + 1)
                    k = pi[k - 1]
            return res

        total = m * n
        row_get = lambda i: grid[i // n][i % n]
        col_get = lambda i: grid[i % m][i // m]
        h = set()
        for s in matches(row_get, total):
            for t in range(s, s + L):
                h.add((t // n, t % n))
        v = set()
        for s in matches(col_get, total):
            for t in range(s, s + L):
                v.add((t % m, t // m))
        return len(h & v)

