var countCells = function(grid, pattern) {
    const m = grid.length, n = grid[0].length, L = pattern.length;
    const pi = new Array(L).fill(0);
    let k = 0;
    for (let i = 1; i < L; i++) {
        while (k > 0 && pattern[i] !== pattern[k]) k = pi[k - 1];
        if (pattern[i] === pattern[k]) k++;
        pi[i] = k;
    }
    const total = m * n;
    const matches = (getch) => {
        const res = [];
        let k = 0;
        for (let i = 0; i < total; i++) {
            const ch = getch(i);
            while (k > 0 && ch !== pattern[k]) k = pi[k - 1];
            if (ch === pattern[k]) k++;
            if (k === L) { res.push(i - L + 1); k = pi[k - 1]; }
        }
        return res;
    };
    const rowGet = (i) => grid[Math.floor(i / n)][i % n];
    const colGet = (i) => grid[i % m][Math.floor(i / m)];
    const h = new Set();
    for (const s of matches(rowGet)) {
        for (let t = s; t < s + L; t++) h.add(Math.floor(t / n) * n + (t % n));
    }
    const v = new Set();
    for (const s of matches(colGet)) {
        for (let t = s; t < s + L; t++) v.add((t % m) * n + Math.floor(t / m));
    }
    let cnt = 0;
    for (const c of v) if (h.has(c)) cnt++;
    return cnt;
};
